    for (let i = live.length - 1; i >= 0; i--) {
      if (!live[i].root.isConnected) {
        live[i].builder.destroy();
        live.splice(i, 1);
      }
    }
    const host = scope || document;
    const roots = Array.from(
      host.querySelectorAll("[data-dz-dashboard-builder]"),
    );
